import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  ConfigureTraefikDomainSchema,
  UpdateDomainSchema,
  DeleteDomainSchema,
  SetupTraefikSchema,
  ServerIdOnlySchema,
  GetCertificateInfoSchema,
  GetTraefikLogsSchema,
  UpdateTraefikEmailSchema,
} from './types';
import { TraefikService } from '../services/TraefikService';
import { TraefikDomainService } from '../services/TraefikDomainService';
import { ReverseProxyDetector } from '../services/ReverseProxyDetector';
import { sshService } from '../services/SSHService';

const traefikService = new TraefikService();
const domainService = new TraefikDomainService();

export interface ApiResult<T> {
  success: boolean;
  data?: T;
  error?: string;
}

export function registerTraefikHandlers() {
  /**
   * Setup Traefik on a server
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_SETUP, async (_, input) => {
    try {
      const validated = SetupTraefikSchema.parse(input);
      await traefikService.setupTraefik(validated.serverId, validated.email);

      return {
        success: true,
        data: { message: 'Traefik installed successfully' },
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Traefik setup error:', error);
      return {
        success: false,
        error: error.message || 'Failed to setup Traefik',
      } as ApiResult<any>;
    }
  });

  /**
   * Check if Traefik is installed
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_IS_INSTALLED, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const isInstalled = await traefikService.isTraefikInstalled(validated.serverId);

      return {
        success: true,
        data: { isInstalled },
      } as ApiResult<{ isInstalled: boolean }>;
    } catch (error: any) {
      console.error('Traefik check error:', error);
      return {
        success: false,
        error: error.message || 'Failed to check Traefik status',
      } as ApiResult<any>;
    }
  });

  /**
   * Get Traefik version
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_GET_VERSION, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const version = await traefikService.getTraefikVersion(validated.serverId);

      return {
        success: true,
        data: { version },
      } as ApiResult<{ version: string }>;
    } catch (error: any) {
      console.error('Get Traefik version error:', error);
      return {
        success: false,
        error: error.message || 'Failed to get Traefik version',
      } as ApiResult<any>;
    }
  });

  /**
   * Restart Traefik
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_RESTART, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      await traefikService.restartTraefik(validated.serverId);

      return {
        success: true,
        data: { message: 'Traefik restarted successfully' },
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Restart Traefik error:', error);
      return {
        success: false,
        error: error.message || 'Failed to restart Traefik',
      } as ApiResult<any>;
    }
  });

  /**
   * Get Traefik logs
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_GET_LOGS, async (_, input) => {
    try {
      const validated = GetTraefikLogsSchema.parse(input);
      const logs = await traefikService.getTraefikLogs(
        validated.serverId,
        validated.lines || 100
      );

      return {
        success: true,
        data: { logs },
      } as ApiResult<{ logs: string }>;
    } catch (error: any) {
      console.error('Get Traefik logs error:', error);
      return {
        success: false,
        error: error.message || 'Failed to get Traefik logs',
      } as ApiResult<any>;
    }
  });

  /**
   * Configure domain with Traefik
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DOMAIN_CONFIGURE, async (_, input) => {
    try {
      const validated = ConfigureTraefikDomainSchema.parse(input);
      const configured = await domainService.configureDomain(validated as any);

      return {
        success: true,
        data: {
          domainId: configured.domainId,
          stackAssociated: configured.stackAssociated,
          stackId: configured.stackId,
          message: 'Domain configured successfully',
        },
      } as ApiResult<{ domainId: string; message: string; stackAssociated?: boolean; stackId?: string | null }>;
    } catch (error: any) {
      console.error('Configure domain error:', error);
      return {
        success: false,
        error: error.message || 'Failed to configure domain',
      } as ApiResult<any>;
    }
  });

  /**
   * Update domain configuration
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DOMAIN_UPDATE, async (_, input) => {
    console.log(`[IPC.TRAEFIK_DOMAIN_UPDATE] Received input:`, JSON.stringify(input, null, 2));
    try {
      const validated = UpdateDomainSchema.parse(input);
      console.log(`[IPC.TRAEFIK_DOMAIN_UPDATE] Validated input:`, JSON.stringify(validated, null, 2));
      const result = await domainService.updateDomain(validated.domainId, validated as any);

      // Check if the result indicates a redeploy is needed
      if (result.requiresRedeploy) {
        console.log(`[IPC.TRAEFIK_DOMAIN_UPDATE] Port change requires redeploy - returning requiresRedeploy=true`);
        return {
          success: true,
          data: {
            requiresRedeploy: true,
            currentPort: result.currentPort,
            newPort: result.newPort,
            message: result.message,
          },
        } as ApiResult<any>;
      }

      console.log(`[IPC.TRAEFIK_DOMAIN_UPDATE] Update completed successfully`);
      return {
        success: true,
        data: { message: 'Domain updated successfully' },
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('[IPC.TRAEFIK_DOMAIN_UPDATE] Update domain error:', error);
      return {
        success: false,
        error: error.message || 'Failed to update domain',
      } as ApiResult<any>;
    }
  });

  /**
   * Delete domain
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DOMAIN_DELETE, async (_, input) => {
    try {
      const validated = DeleteDomainSchema.parse(input);
      await domainService.deleteDomain(validated.domainId);

      return {
        success: true,
        data: { message: 'Domain deleted successfully' },
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Delete domain error:', error);
      return {
        success: false,
        error: error.message || 'Failed to delete domain',
      } as ApiResult<any>;
    }
  });

  /**
   * List domains for a server
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DOMAIN_LIST, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const domains = await domainService.getDomainsByServer(validated.serverId);

      return {
        success: true,
        data: domains,
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('List domains error:', error);
      return {
        success: false,
        error: error.message || 'Failed to list domains',
      } as ApiResult<any>;
    }
  });

  /**
   * Get domain by ID
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DOMAIN_GET, async (_, domainId: string) => {
    try {
      const domain = await domainService.getDomainById(domainId);

      if (!domain) {
        return {
          success: false,
          error: 'Domain not found',
        } as ApiResult<any>;
      }

      return {
        success: true,
        data: domain,
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Get domain error:', error);
      return {
        success: false,
        error: error.message || 'Failed to get domain',
      } as ApiResult<any>;
    }
  });

  /**
   * Get certificate info for a domain
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_CERTIFICATE_INFO, async (_, input) => {
    try {
      const validated = GetCertificateInfoSchema.parse(input);
      const certInfo = await traefikService.getCertificateInfo(
        validated.serverId,
        validated.domain
      );

      return {
        success: true,
        data: certInfo,
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Get certificate info error:', error);
      return {
        success: false,
        error: error.message || 'Failed to get certificate info',
      } as ApiResult<any>;
    }
  });

  /**
   * Get Traefik configuration (including email)
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_GET_CONFIG, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const config = await traefikService.getTraefikConfig(validated.serverId);

      return {
        success: true,
        data: config,
      } as ApiResult<{ email: string | null; dashboardEnabled: boolean; httpRedirect: boolean }>;
    } catch (error: any) {
      console.error('Get Traefik config error:', error);
      return {
        success: false,
        error: error.message || 'Failed to get Traefik config',
      } as ApiResult<any>;
    }
  });

  /**
   * Update Traefik email configuration
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_UPDATE_EMAIL, async (_, input) => {
    try {
      const validated = UpdateTraefikEmailSchema.parse(input);
      await traefikService.updateTraefikEmail(validated.serverId, validated.email);

      return {
        success: true,
        data: { message: 'Email updated successfully' },
      } as ApiResult<{ message: string }>;
    } catch (error: any) {
      console.error('Update Traefik email error:', error);
      return {
        success: false,
        error: error.message || 'Failed to update Traefik email',
      } as ApiResult<any>;
    }
  });

  /**
   * Remove global HTTP-to-HTTPS redirect from Traefik config
   * This allows per-domain Force HTTPS settings to work
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_REMOVE_GLOBAL_REDIRECT, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const removed = await traefikService.removeGlobalHttpRedirect(validated.serverId);

      return {
        success: true,
        data: { removed, message: removed ? 'Global HTTP redirect removed' : 'No global redirect found' },
      } as ApiResult<{ removed: boolean; message: string }>;
    } catch (error: any) {
      console.error('Remove global HTTP redirect error:', error);
      return {
        success: false,
        error: error.message || 'Failed to remove global HTTP redirect',
      } as ApiResult<any>;
    }
  });

  /**
   * Detect existing reverse proxies on the server
   */
  ipcMain.handle(IPC_CHANNELS.TRAEFIK_DETECT_REVERSE_PROXY, async (_, input) => {
    try {
      const validated = ServerIdOnlySchema.parse(input);
      const client = await sshService.connect(validated.serverId);

      if (!client) {
        return {
          success: false,
          error: 'Failed to establish SSH connection',
        } as ApiResult<any>;
      }

      const detection = await ReverseProxyDetector.detect(client);

      return {
        success: true,
        data: detection,
      } as ApiResult<any>;
    } catch (error: any) {
      console.error('Detect reverse proxy error:', error);
      return {
        success: false,
        error: error.message || 'Failed to detect reverse proxy',
      } as ApiResult<any>;
    }
  });
}
